if we add
```
	toV1alpha1Request := func(name string, req metadata.DeviceMetadataRequest) v1alpha1.DeviceMetadataRequest {
		devices := make([]v1alpha1.Device, 0, len(req.Devices))
		for _, device := range req.Devices {
			devices = append(devices, v1alpha1.Device{
				Driver:      device.Driver,
				Pool:        device.Pool,
				Name:        device.Name,
				Attributes:  device.Attributes,
				NetworkData: device.NetworkData,
			})
		}
		return v1alpha1.DeviceMetadataRequest{
			Name:    name,
			Devices: devices,
		}
	}
```

then we can use (on more places as well potentially)
```
	primaryDriverJSON := mustMarshal(&v1alpha1.DeviceMetadata{
		TypeMeta:   metav1.TypeMeta{APIVersion: v1alpha1.SchemeGroupVersion.String(), Kind: "DeviceMetadata"},
		ObjectMeta: metav1.ObjectMeta{Name: "my-claim", Namespace: "default", UID: "uid-1234", Generation: 1},
		Requests: []v1alpha1.DeviceMetadataRequest{
			toV1alpha1Request("gpu-0", gpuInternal),
			toV1alpha1Request("single-gpu", gpuInternal),
			toV1alpha1Request("gpu-1", gpuInternal),
		},
	})
	secondaryDriverJSON := mustMarshal(&v1alpha1.DeviceMetadata{
		TypeMeta:   metav1.TypeMeta{APIVersion: v1alpha1.SchemeGroupVersion.String(), Kind: "DeviceMetadata"},
		ObjectMeta: metav1.ObjectMeta{Name: "my-claim", Namespace: "default", UID: "uid-1234", Generation: 1},
		Requests: []v1alpha1.DeviceMetadataRequest{
			toV1alpha1Request("gpu-0", gpuAltInternal),
			toV1alpha1Request("gpu-1", gpuAltInternal),
		},
	})
```

